function buildOrg() {
  const map = {};
  ORG_RAW.trim().split("\n").forEach(line => {
    const [a, b, c] = line.split("\t");
    if (!map[a]) map[a] = {};
    if (!map[a][b]) map[a][b] = [];
    map[a][b].push(c);
  });
  return map;
}
const ORG = buildOrg();

// 역방향 조회: 지점→{region,center}, 비전센터→region
const BRANCH_LOOKUP = {};
const CENTER_LOOKUP = {};
const ALL_BRANCHES = [];
ORG_RAW.trim().split("\n").forEach(line => {
  const [a, b, c] = line.split("\t");
  BRANCH_LOOKUP[c] = { region: a, center: b };
  CENTER_LOOKUP[b] = a;
  ALL_BRANCHES.push(c);
});

